const trigger = $('Extract Message Data').first().json;
const leadDb  = $('Get Lead Status').first().json || {};

const pausado = leadDb.pausado || leadDb.Pausado || false;
if (pausado === true) {
  return [{ json: { etapa: 'pausado', pausado: true, lead_data: leadDb, trigger } }];
}

let etapa = (leadDb.Etapa || leadDb.etapa || 'qualificacao').toLowerCase().trim();
const validas = ['qualificacao','negociacao','pagamento','handoff'];
if (!validas.includes(etapa)) etapa = 'qualificacao';

// "nova" e ausência → qualificacao
if (etapa === 'nova') etapa = 'qualificacao';

return [{ json: {
  etapa,
  pausado: false,
  lead_data: leadDb,
  trigger,
  chatid:          trigger.chatid,
  mensagem:        trigger.mensagem,
  urlchatwoot:     trigger.urlchatwoot,
  account_id:      trigger.account_id,
  conversation_id: trigger.conversation_id,
  chatwoottoken:   trigger.chatwoottoken,
  contact_id:      trigger.contact_id
} }];

const message1 = $json.Message1;
const message2 = $json.Message2;

// Se Message2 for null/vazio, pode seguir
if (!message2) {
  const mensagemCompleta = [...message1].reverse().join("\n");
  return [{
    json: {
      mensagem: mensagemCompleta,
      resultado: true
    }
  }];
}

const saoIguais = JSON.stringify(message1) === JSON.stringify(message2);

if (!saoIguais) {
  return [{
    json: {
      resultado: false
    }
  }];
}

const mensagemCompleta = [...message1].reverse().join("\n");
return [{
  json: {
    mensagem: mensagemCompleta,
    resultado: true
  }
}];
